#!/usr/bin/env bash
# Seed blog posts into a deployed Temp Mail site (KV-backed). AUTO-GENERATED by blog-assemble.py.
# Usage: BASE_URL='https://your-domain.com' DASHBOARD_PASSWORD='your-owner-pw' ./scripts/seed-blog.sh
set -euo pipefail
BASE_URL="${BASE_URL:-http://127.0.0.1:5050}"
DASHBOARD_PASSWORD="${DASHBOARD_PASSWORD:-12345}"
API="$BASE_URL/api/admin/posts?pw=$DASHBOARD_PASSWORD"
post () { curl -fsS -X POST "$API" -H "Content-Type: application/json" -d @- >/dev/null && echo "  seeded: $1"; }
echo "Seeding blog posts to $BASE_URL ..."

