SEED_LOCALES="${SEED_LOCALES:-de,fr,es,nl,it}"
if [[ -n "$SEED_LOCALES" && "$SEED_LOCALES" != "none" ]]; then
  SEED_LOCALES="$SEED_LOCALES" BASE_URL="$BASE_URL" DASHBOARD_PASSWORD="$DASHBOARD_PASSWORD" node <<'NODE'
const base = process.env.BASE_URL.replace(/\/+$/, "");
const pw = encodeURIComponent(process.env.DASHBOARD_PASSWORD || "");
const locales = (process.env.SEED_LOCALES || "").split(",").map((s) => s.trim()).filter(Boolean);
for (const locale of locales) {
  const indexUrl = `${base}/api/admin/posts?pw=${pw}&locale=${encodeURIComponent(locale)}`;
  const indexRes = await fetch(indexUrl);
  if (!indexRes.ok) throw new Error(`index ${locale}: ${indexRes.status}`);
  const index = await indexRes.json();
  for (const meta of index.posts || []) {
    const slug = meta.slug || meta;
    const getUrl = `${base}/api/admin/posts?pw=${pw}&locale=${encodeURIComponent(locale)}&slug=${encodeURIComponent(slug)}`;
    const getRes = await fetch(getUrl);
    if (!getRes.ok) throw new Error(`post ${locale}/${slug}: ${getRes.status}`);
    const data = await getRes.json();
    if (!data.post) continue;
    data.post.locale = locale;
    const postRes = await fetch(`${base}/api/admin/posts?pw=${pw}&locale=${encodeURIComponent(locale)}`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(data.post),
    });
    if (!postRes.ok) throw new Error(`save ${locale}/${slug}: ${postRes.status}`);
    console.log(`  seeded: ${locale}/${slug}`);
  }
}
NODE
fi

echo "Done."
